+   */
+  get busyWorkerCount(): number {
+    return 0;
+  }
+
+  /**
+   * Get the queue length
+   */
+  get queueLength(): number {
+    return 0;
+  }
+
+  /**
+   * Destroy the pool
+   */
+  destroy(): void {
+    this.destroyed = true;
+  }
+}
+
+// Singleton instance for convenience
+let defaultPool: CompressionPool | null = null;
+
+/**
